// ---- result_json helpers ----

export function extractEvidence(violationType: string, result: any): string {
  if (!result) return ''
  switch (violationType) {
    case 'manager_escalation': {
      const areas = result?.call_overview?.manager_focus_areas
      return Array.isArray(areas)
        ? areas.map((a: any) => a?.quote).filter(Boolean).join('; ')
        : ''
    }
    case 'budget_compliance':
      return result?.key_evidence_quote || ''
    case 'warm_transfer':
      return result?.warm_transfer_compliance?.violation_reason || ''
    case 'litigation_check':
      return result?.key_evidence_quote || ''
    case 'program_expectations':
      return result?.key_evidence_quote || ''
    default:
      return ''
  }
}

export function extractReason(violationType: string, result: any): string {
  if (!result) return ''
  switch (violationType) {
    case 'manager_escalation':
      return result?.call_overview?.manager_review_reason || ''
    case 'budget_compliance':
      return result?.violation_reason || ''
    case 'warm_transfer':
      return result?.warm_transfer_compliance?.violation_reason || ''
    case 'litigation_check':
      return result?.violation_reason || ''
    case 'program_expectations':
      return result?.violation_reason || ''
    default:
      return ''
  }
}
